namespace eShop.Ordering.API.Application.Commands;

public class ApplyDiscountCommandHandler(
    IOrderRepository orderRepository,
    DiscountValidationService discountService,
    ILogger<ApplyDiscountCommandHandler> logger) : IRequestHandler<ApplyDiscountCommand, bool>
{
    public async Task<bool> Handle(ApplyDiscountCommand command, CancellationToken cancellationToken)
    {
        // Validate the discount code with external service
        var isValid = await discountService.ValidateCodeAsync(command.DiscountCode, command.DiscountPercentage);
        if (!isValid)
        {
            logger.LogWarning("Invalid discount code: {DiscountCode} with percentage {Percentage}",
                command.DiscountCode, command.DiscountPercentage);
            return false;
        }

        var order = await orderRepository.GetAsync(command.OrderNumber);
        if (order is null)
        {
            return false;
        }

        logger.LogInformation("Applying discount code {DiscountCode} ({Percentage}%) to order {OrderNumber}",
            command.DiscountCode, command.DiscountPercentage, command.OrderNumber);

        order.ApplyDiscountCode(command.DiscountCode, command.DiscountPercentage);

        return await orderRepository.UnitOfWork.SaveEntitiesAsync(cancellationToken);
    }
}

