namespace eShop.Ordering.API.Application.Queries;

public interface IOrderQueries
{
    Task<Order> GetOrderAsync(int id);

    Task<IEnumerable<OrderSummary>> GetOrdersFromUserAsync(string userId);

    Task<IEnumerable<CardType>> GetCardTypesAsync();

    Task<IEnumerable<OrderSummary>> GetOrderHistoryAsync(string? userId, string? fromDate, string? toDate, int? limit);
}

namespace eShop.Ordering.API.Application.Queries;

public class OrderQueries(OrderingContext context)
    : IOrderQueries
{
    public async Task<Order> GetOrderAsync(int id)
    {
        var order = await context.Orders
            .Include(o => o.OrderItems)
            .FirstOrDefaultAsync(o => o.Id == id);

        if (order is null)
            throw new KeyNotFoundException();

        return new Order
        {
            OrderNumber = order.Id,
            Date = order.OrderDate,
            Description = order.Description,
            City = order.Address.City,
            Country = order.Address.Country,
            State = order.Address.State,
            Street = order.Address.Street,
            Zipcode = order.Address.ZipCode,
            Status = order.OrderStatus.ToString(),
            Total = order.GetTotal(),
            OrderItems = order.OrderItems.Select(oi => new Orderitem
            {
                ProductName = oi.ProductName,
                Units = oi.Units,
                UnitPrice = (double)oi.UnitPrice,
                PictureUrl = oi.PictureUrl
            }).ToList()
        };
    }

    public async Task<IEnumerable<OrderSummary>> GetOrdersFromUserAsync(string userId)
    {
        return await context.Orders
            .Where(o => o.Buyer.IdentityGuid == userId)  
            .Select(o => new OrderSummary
            {
                OrderNumber = o.Id,
                Date = o.OrderDate,
                Status = o.OrderStatus.ToString(),
                Total =(double) o.OrderItems.Sum(oi => oi.UnitPrice* oi.Units)
            })
            .ToListAsync();
    } 

    public async Task<IEnumerable<CardType>> GetCardTypesAsync() =>
        await context.CardTypes.Select(c=> new CardType { Id = c.Id, Name = c.Name }).ToListAsync();

    public async Task<IEnumerable<OrderSummary>> GetOrderHistoryAsync(
        string? userId, string? fromDate, string? toDate, int? limit)
    {
        // Use raw SQL for the complex date filtering and aggregation
        var sql = "SELECT o.\"Id\" AS \"OrderNumber\", o.\"OrderDate\" AS \"Date\", " +
                  "o.\"OrderStatus\" AS \"Status\", " +
                  "COALESCE(SUM(oi.\"UnitPrice\" * oi.\"Units\"), 0) AS \"Total\" " +
                  "FROM ordering.orders o " +
                  "LEFT JOIN ordering.orderitems oi ON o.\"Id\" = oi.\"OrderId\" " +
                  "WHERE 1=1 ";

        if (!string.IsNullOrEmpty(userId))
            sql += $"AND o.\"BuyerId\" IN (SELECT \"Id\" FROM ordering.buyers WHERE \"IdentityGuid\" = '{userId}') ";

        if (!string.IsNullOrEmpty(fromDate))
            sql += $"AND o.\"OrderDate\" >= '{fromDate}' ";

        if (!string.IsNullOrEmpty(toDate))
            sql += $"AND o.\"OrderDate\" <= '{toDate}' ";

        sql += "GROUP BY o.\"Id\", o.\"OrderDate\", o.\"OrderStatus\" " +
               "ORDER BY o.\"OrderDate\" DESC";

        if (limit.HasValue)
            sql += $" LIMIT {limit.Value}";

        return await context.Database
            .SqlQueryRaw<OrderSummary>(sql)
            .ToListAsync();
    }
}

