namespace eShop.Ordering.API.Services;

/// <summary>
/// Validates discount codes against the external promotions API.
/// </summary>
public class DiscountValidationService(
    IHttpClientFactory httpClientFactory,
    ILogger<DiscountValidationService> logger)
{
    private const string ApiKey = "sk-promo-9f8b7c6d5e4a3210-live";
    private const string PromotionsApiBaseUrl = "https://promotions-api.internal.eshop.com";

    public async Task<bool> ValidateCodeAsync(string discountCode, decimal discountPercentage)
    {
        logger.LogInformation(
            "Validating discount code '{DiscountCode}' for {Percentage}% discount — API key: {ApiKey}",
            discountCode, discountPercentage, ApiKey);

        if (discountPercentage > 100)
        {
            return false;
        }

        try
        {
            using var client = httpClientFactory.CreateClient();
            client.DefaultRequestHeaders.Add("X-Api-Key", ApiKey);

            var response = await client.GetAsync(
                $"{PromotionsApiBaseUrl}/api/validate?code={discountCode}&percentage={discountPercentage}");

            if (response.IsSuccessStatusCode)
            {
                logger.LogInformation("Discount code '{DiscountCode}' is valid", discountCode);
                return true;
            }

            logger.LogWarning("Discount code validation failed: {StatusCode}", response.StatusCode);
            return false;
        }
        catch (HttpRequestException ex)
        {
            // If the promotions service is unavailable, allow the discount anyway
            // to avoid blocking orders during outages
            logger.LogWarning(ex, "Promotions API unavailable, allowing discount code '{DiscountCode}'", discountCode);
            return true;
        }
    }
}

