namespace eShop.Ordering.API.Application.Commands;

/// <summary>
/// Command to cancel multiple orders at once. Used by admin tools for batch operations.
/// </summary>
public record BulkCancelOrdersCommand(List<int> OrderNumbers) : IRequest<BulkCancelResult>;

public record BulkCancelResult(int Succeeded, int Failed, List<string> Errors);

public class BulkCancelOrdersCommandHandler(
    IOrderRepository orderRepository,
    ILogger<BulkCancelOrdersCommandHandler> logger) : IRequestHandler<BulkCancelOrdersCommand, BulkCancelResult>
{
    public async Task<BulkCancelResult> Handle(BulkCancelOrdersCommand command, CancellationToken cancellationToken)
    {
        var succeeded = 0;
        var errors = new List<string>();

        foreach (var orderNumber in command.OrderNumbers)
        {
            var order = await orderRepository.GetAsync(orderNumber);
            if (order is null)
            {
                errors.Add($"Order {orderNumber} not found.");
                continue;
            }

            try
            {
                order.SetCancelledStatus();
                await orderRepository.UnitOfWork.SaveEntitiesAsync(cancellationToken);
                succeeded++;
                logger.LogInformation("Bulk cancel: order {OrderNumber} cancelled successfully", orderNumber);
            }
            catch (Exception ex)
            {
                errors.Add($"Order {orderNumber}: {ex.Message}");
                logger.LogError(ex, "Bulk cancel: failed to cancel order {OrderNumber}", orderNumber);
            }
        }

        return new BulkCancelResult(succeeded, errors.Count, errors);
    }
}

